-- Insert 50 speed / sprinter quick-release exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Wall Drill Iso Lean March', 'wall-drill-iso-lean-march', 'Wall Drill Iso Lean March is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes ankle dorsiflexion, hip flexion, hip extension while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 6, 30, 30, 60, 'Wall-supported acceleration posture drill that teaches whole-body lean, shin angle, and marching rhythm before starts.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Posture Mechanics', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["ankle_dorsiflexion","hip_flexion","hip_extension","trunk_bracing"],"primary_tissues":["hip_flexors","glutes","calves","abdominals"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Wall-supported acceleration posture drill that teaches whole-body lean, shin angle, and marching rhythm before starts.","setup":["Face a wall with hands at shoulder height and body in a straight diagonal line.","Walk feet back until the athlete can feel a long push through the stance leg.","Brace ribs over pelvis and keep head in line with spine."],"execution_steps":["Drive one knee up to hip height without collapsing the stance leg.","Hold the lean and alternate controlled marching reps.","Reset posture if hips pike, ribs flare, or heel drops."],"coach_cues":["Push the wall away","Long line from ear to ankle","Knee punches up; stance foot pushes down and back"],"common_faults":["Hips folding behind the body","Low heel or soft ankle","Overreaching knee drive without trunk control"]}'::jsonb),
  ('Wall Drill Fast Switch', 'wall-drill-fast-switch', 'Wall Drill Fast Switch is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes hip flexion, hip extension, ankle stiffness while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 5, 20, 40, 60, 'A sharper wall-supported switch drill that links acceleration posture to rapid limb exchange.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Posture Mechanics', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["hip_flexion","hip_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["hip_flexors","glutes","calves","hamstrings"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"A sharper wall-supported switch drill that links acceleration posture to rapid limb exchange.","setup":["Set the same diagonal wall-lean position as the iso march.","Start with one knee driven up and the stance leg long."],"execution_steps":["On the coach cue, switch legs quickly while keeping the trunk angle fixed.","Land under the hip on a stiff forefoot.","Pause briefly to show control before the next switch."],"coach_cues":["Switch fast, land tall","Brace before you switch","Foot strikes down and back"],"common_faults":["Bouncing out of the lean","Cycling the foot behind the hip","Switching so fast posture is lost"]}'::jsonb),
  ('A-March', 'a-march', 'A-March is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes hip flexion, hip extension, ankle dorsiflexion while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 25, 25, 55, 'Foundational marching drill for tall posture, front-side mechanics, dorsiflexion, and arm-leg timing.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Drill Series', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["hip_flexion","hip_extension","ankle_dorsiflexion","contralateral_arm_swing"],"primary_tissues":["hip_flexors","glutes","calves","abdominals"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"Foundational marching drill for tall posture, front-side mechanics, dorsiflexion, and arm-leg timing.","setup":["Mark a 10-20 m lane.","Stand tall with ribs stacked, eyes forward, and elbows near 90 degrees."],"execution_steps":["March forward with knee to hip height and toe pulled up.","Strike the ground under the hip with a crisp downstroke.","Coordinate opposite arm and leg without leaning back."],"coach_cues":["Tall hips","Toe up, step down","Arms cheek to pocket"],"common_faults":["Leaning back to lift the knee","Foot landing ahead of the body","Cross-body arm swing"]}'::jsonb),
  ('A-Skip', 'a-skip', 'A-Skip is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes hip flexion, hip extension, ankle dorsiflexion while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 20, 40, 65, 'Rhythmic skip that adds elastic timing to the A-march pattern without turning it into conditioning.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Drill Series', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["hip_flexion","hip_extension","ankle_dorsiflexion","elastic_foot_contact"],"primary_tissues":["hip_flexors","calves","glutes","hamstrings"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Rhythmic skip that adds elastic timing to the A-march pattern without turning it into conditioning.","setup":["Use a 10-20 m lane with enough spacing.","Start tall with active arms and a quiet upper body."],"execution_steps":["Skip forward, driving the knee up and striking down under the hip.","Keep contacts springy but controlled.","Walk back for recovery and repeat only while rhythm is crisp."],"coach_cues":["Pop off the ground","Knee up, foot down","Relax the face and shoulders"],"common_faults":["Bounding too high","Foot reaching in front","Arms crossing midline"]}'::jsonb),
  ('Low Dribble Run', 'low-dribble-run', 'Low Dribble Run is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes ankle stiffness, hip flexion, hip extension while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 20, 40, 65, 'Low-amplitude dribble that teaches fast foot recovery, stiffness, and ground strike under the hips.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Drill Series', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["ankle_stiffness","hip_flexion","hip_extension"],"primary_tissues":["calves","hip_flexors","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Low-amplitude dribble that teaches fast foot recovery, stiffness, and ground strike under the hips.","setup":["Mark a 10-20 m lane.","Stand tall with small steps and active arms."],"execution_steps":["Cycle the foot low and fast as if stepping over a low hurdle.","Keep the strike under the hips with a stiff ankle.","Progress to slightly faster cadence without losing posture."],"coach_cues":["Small wheel under the hip","Step down, not forward","Quiet shoulders"],"common_faults":["Foot casting forward","Excessive knee lift","Upper body bouncing"]}'::jsonb),
  ('High Dribble Run', 'high-dribble-run', 'High Dribble Run is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes hip flexion, ankle stiffness, front side cycle while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 25, 45, 75, 'Higher dribble pattern that brings the sprint cycle closer to upright running while preserving rhythm and control.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Drill Series', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["hip_flexion","ankle_stiffness","front_side_cycle"],"primary_tissues":["hip_flexors","calves","hamstrings"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Higher dribble pattern that brings the sprint cycle closer to upright running while preserving rhythm and control.","setup":["Mark a 15-25 m lane.","Begin tall with the pelvis level and arms active."],"execution_steps":["Cycle the thigh higher than the low dribble while striking under the hip.","Keep the foot path circular and compact.","Build speed only when contacts stay stiff and quiet."],"coach_cues":["Wheel up, strike down","Tall through the crown","Fast but smooth"],"common_faults":["Overstriding","Leaning back","Chasing speed before rhythm"]}'::jsonb),
  ('Ankling Drill', 'ankling-drill', 'Ankling Drill is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes ankle dorsiflexion, forefoot contact, elastic ankle rocker while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 15, 30, 50, 'Tiny, rapid ankle-driven steps that build awareness of foot strike, stiffness, and rhythm for sprint contacts.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Foot-Ankle Rhythm', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["ankle_dorsiflexion","forefoot_contact","elastic_ankle_rocker"],"primary_tissues":["calves","soleus","plantar_intrinsics","tibialis_anterior"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"Tiny, rapid ankle-driven steps that build awareness of foot strike, stiffness, and rhythm for sprint contacts.","setup":["Mark a short 10-15 m lane.","Keep posture tall and steps very small."],"execution_steps":["Move forward with quick forefoot contacts and minimal knee lift.","Let the ankle cycle from dorsiflexion to a quick downward strike.","Keep the torso quiet and the cadence smooth."],"coach_cues":["Quick ankles","Step under your hips","Quiet bounce"],"common_faults":["Turning it into a jog","Heel collapsing heavily","Too much knee lift"]}'::jsonb),
  ('Sprint Arm Action Switches', 'sprint-arm-action-switches', 'Sprint Arm Action Switches is a sprint access & mechanics exercise for speed, sprinting, and quick-release athletes. It emphasizes shoulder flexion extension, scapular control, trunk bracing while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, NULL, 15, 30, 50, 'Arm-action drill that teaches relaxed, rapid arm exchange without trunk rotation or shoulder tension.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need sprint access & mechanics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Arm Mechanics', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["shoulder_flexion_extension","scapular_control","trunk_bracing"],"primary_tissues":["deltoids","lats","obliques","abdominals"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Arm-action drill that teaches relaxed, rapid arm exchange without trunk rotation or shoulder tension.","setup":["Stand tall or split stance with elbows near 90 degrees.","Set ribs over pelvis and keep eyes forward."],"execution_steps":["Switch the arms from cheek-to-pocket positions on command.","Keep shoulders relaxed and hands loose.","Progress cadence while the trunk stays quiet."],"coach_cues":["Cheek to pocket","Loose hands, fast elbows","Ribs stay quiet"],"common_faults":["Crossing the midline","Shrugging the shoulders","Rotating the torso"]}'::jsonb),
  ('Falling Start 10m', 'falling-start-10m', 'Falling Start 10m is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes forward lean projection, hip extension, ankle stiffness while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 3, 90, 95, 'Simple acceleration start that teaches the athlete to project the body before sprinting out.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Acceleration Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["forward_lean_projection","hip_extension","ankle_stiffness","contralateral_arm_drive"],"primary_tissues":["glutes","hamstrings","calves","hip_flexors"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Simple acceleration start that teaches the athlete to project the body before sprinting out.","setup":["Set a start cone and finish cone 10 m away.","Stand tall, rise onto the balls of the feet, and slowly fall forward."],"execution_steps":["Let the body fall as one piece until a step is required.","Punch the first step down and back to catch the fall.","Sprint through 10 m and walk back fully recovered."],"coach_cues":["Fall first, then punch","Push the ground back","Run through the line"],"common_faults":["Stepping before the body falls","Popping upright too early","Stopping at the finish line"]}'::jsonb),
  ('2-Point Start 10-20m', '2-point-start-10-20m', '2-Point Start 10-20m is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, knee drive, trunk projection while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 4, 120, 125, 'Primary field-sport acceleration start for first-step power, projection, and clean shin angles.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Acceleration Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["hip_extension","knee_drive","trunk_projection","arm_drive"],"primary_tissues":["glutes","hamstrings","calves","hip_flexors"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Primary field-sport acceleration start for first-step power, projection, and clean shin angles.","setup":["Set a 10-20 m lane.","Use a staggered stance with front shin angled forward and opposite arm loaded."],"execution_steps":["Drive out hard without popping upright.","Push for the first 3-5 steps before gradually rising.","Recover fully between attempts."],"coach_cues":["Push, push, push","Eyes down early","Big split, violent arms"],"common_faults":["False step backward","Standing up on step one","Reaching the first foot too far in front"]}'::jsonb),
  ('3-Point Start 10-20m', '3-point-start-10-20m', '3-Point Start 10-20m is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, arm drive, trunk projection while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 4, 120, 125, 'Track-style or football-style start that loads projection angles and aggressive first-step force.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Acceleration Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["hip_extension","arm_drive","trunk_projection","ankle_stiffness"],"primary_tissues":["glutes","hamstrings","calves","hip_flexors","shoulder_stabilizers"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Track-style or football-style start that loads projection angles and aggressive first-step force.","setup":["Place one hand on the ground under the shoulder and stagger the feet.","Load the hips slightly above the shoulders without rounding the back."],"execution_steps":["Push both feet hard and rip the opposite arm forward.","Stay low through the first few steps.","Sprint through the target distance and recover fully."],"coach_cues":["Load, push, rip","Keep the tunnel low","First step down and back"],"common_faults":["Weight too far on the hand","First step landing ahead of the hip","Hips shooting up before the push"]}'::jsonb),
  ('Push-Up Start 10m', 'push-up-start-10m', 'Push-Up Start 10m is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal push, hip extension, rapid ground reorientation while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 5, 120, 125, 'Prone reactive start that challenges quick reorientation, first-step violence, and acceleration intent.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Reactive Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["horizontal_push","hip_extension","rapid_ground_reorientation"],"primary_tissues":["pecs","triceps","glutes","hamstrings","calves"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Prone reactive start that challenges quick reorientation, first-step violence, and acceleration intent.","setup":["Lie prone behind a start cone with hands under shoulders.","Set a finish cone 10 m away and clear the lane."],"execution_steps":["On the cue, press up and step into acceleration.","Drive out low and sprint through the finish cone.","Walk back and rest fully."],"coach_cues":["Pop, plant, push","Do not stand up first","Win the first three steps"],"common_faults":["Taking too long to rise","Stepping across the body","Turning it into conditioning"]}'::jsonb),
  ('Split-Stance Drop-In Start', 'split-stance-drop-in-start', 'Split-Stance Drop-In Start is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, rapid weight shift, ankle stiffness while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 3, 90, 95, 'Drop-in start that teaches pre-tension, rapid weight shift, and immediate projection out of a split stance.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Acceleration Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["hip_extension","rapid_weight_shift","ankle_stiffness"],"primary_tissues":["glutes","hamstrings","calves","quads"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Drop-in start that teaches pre-tension, rapid weight shift, and immediate projection out of a split stance.","setup":["Stand in a split stance with the front foot flat and arms loaded.","Set a 5-15 m sprint lane."],"execution_steps":["Slightly unweight/drop into the front leg.","Immediately punch out into acceleration.","Sprint through the cone and recover fully."],"coach_cues":["Drop and go","No rocking back","Push the track away"],"common_faults":["Rocking backward before moving","Jumping upward","Front knee collapsing inward"]}'::jsonb),
  ('Band-Resisted First Step', 'band-resisted-first-step', 'Band-Resisted First Step is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal projection, hip extension, trunk bracing while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 4, 120, 125, 'Partner- or band-resisted first-step drill that overloads projection without turning sprinting into slow grinding.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Resisted Acceleration', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["horizontal_projection","hip_extension","trunk_bracing"],"primary_tissues":["glutes","hamstrings","calves","abdominals"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Partner- or band-resisted first-step drill that overloads projection without turning sprinting into slow grinding.","setup":["Anchor a band around the athlete waist with a partner behind.","Set a 5-10 m lane and create only light-moderate tension."],"execution_steps":["Assume a 2-point start.","Drive out against the band for 3-5 explosive steps.","Partner releases or follows safely as the athlete finishes the short sprint."],"coach_cues":["Push the band, do not pull with the chest","Shins angled, hips through","Fast arms drive the legs"],"common_faults":["Resistance too heavy","Athlete folding at the waist","Dragging contacts behind the hips"]}'::jsonb),
  ('Light Sled 10m Acceleration', 'light-sled-10m-acceleration', 'Light Sled 10m Acceleration is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal projection, hip extension, knee drive while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, NULL, 5, 150, 155, 'Light resisted sprint that overloads projection and force application while keeping sprint rhythm intact.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Resisted Acceleration', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["horizontal_projection","hip_extension","knee_drive","ankle_stiffness"],"primary_tissues":["glutes","hamstrings","calves","quads"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Light resisted sprint that overloads projection and force application while keeping sprint rhythm intact.","setup":["Attach harness or waist belt to a light sled.","Set a 10 m lane and ensure the surface is safe."],"execution_steps":["Start in a strong acceleration stance.","Sprint the sled through 10 m with aggressive pushes.","Rest fully and remove load if mechanics slow excessively."],"coach_cues":["Fast sled, not heavy sled","Push down and back","Keep rising gradually"],"common_faults":["Overloading until speed dies","Hunched shoulders","Overstriding against the sled"]}'::jsonb),
  ('Hill Sprint Acceleration', 'hill-sprint-acceleration', 'Hill Sprint Acceleration is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, knee drive, ankle stiffness while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, NULL, 6, 150, 160, 'Short incline acceleration that encourages projection and limits overstriding while raising force demand.', 'Primary subrole: acceleration_start_speed. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Acceleration Starts', 'output', 'acceleration_start_speed', 'acceleration_start_speed', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","trunk_projection"],"primary_tissues":["glutes","hamstrings","calves","quads"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Short incline acceleration that encourages projection and limits overstriding while raising force demand.","setup":["Choose a mild hill with good traction and no obstacles.","Mark 10-20 m and start from a 2-point stance."],"execution_steps":["Drive uphill with strong forward projection.","Stay smooth and powerful through the line.","Walk down slowly and recover fully."],"coach_cues":["Push the hill away","Hips through the slope","Fast arms, quiet face"],"common_faults":["Hill too steep","Short choppy steps with no projection","Conditioning-style repeat sprints"]}'::jsonb),
  ('Chase Reaction Sprint', 'chase-reaction-sprint', 'Chase Reaction Sprint is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes visual reaction, hip extension, rapid acceleration while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 4, 120, 125, 'Partner chase start that trains perception-action speed, commitment, and first-step acceleration under a live cue.', 'Primary subrole: reactive_agility_tumbling_output. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Reactive Starts', 'output', 'reactive_agility_tumbling_output', 'reactive_agility_tumbling_output', '{"primary_joint_actions":["visual_reaction","hip_extension","rapid_acceleration"],"primary_tissues":["glutes","hamstrings","calves","hip_flexors"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"reactive_output_profile":{"stimulus_type":"coach cue, partner cue, or visual trigger","amplitude_cap":"short distance with full rest","quality_priority":"react first, then express speed"}}'::jsonb, '{"movement_description":"Partner chase start that trains perception-action speed, commitment, and first-step acceleration under a live cue.","setup":["Place two athletes in staggered lanes with 1-2 m spacing.","Define clear start and finish cones over 10-15 m."],"execution_steps":["Leader starts on own timing or coach cue.","Chaser reacts and sprints through the finish.","Rotate roles and maintain full recovery."],"coach_cues":["React, then project","Win the first step","Sprint through the cone"],"common_faults":["Guessing the cue","Reaching across lanes","Too many reps with tired mechanics"]}'::jsonb),
  ('Lateral Open-Step to Sprint', 'lateral-open-step-to-sprint', 'Lateral Open-Step to Sprint is a acceleration & first-step output exercise for speed, sprinting, and quick-release athletes. It emphasizes hip external rotation, lateral push, sprint acceleration while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 1, 4, 90, 100, 'Open-step transition drill for athletes who must rotate, redirect the hips, and release into sprint speed quickly.', 'Primary subrole: deceleration_cod_power. Use this for athletes who need acceleration & first-step output without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Multidirectional First Step', 'output', 'deceleration_cod_power', 'deceleration_cod_power', '{"primary_joint_actions":["hip_external_rotation","lateral_push","sprint_acceleration"],"primary_tissues":["glutes","adductors","hamstrings","calves"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"cod_stress_profile":{"approach_velocity":"low_to_moderate unless marked output","cut_angle":"0-90 degrees depending on setup","quality_priority":"quiet stick, knee/hip/foot alignment"}}'::jsonb, '{"movement_description":"Open-step transition drill for athletes who must rotate, redirect the hips, and release into sprint speed quickly.","setup":["Set a start cone and a finish cone 5-10 m away at a 45-90 degree angle.","Athlete starts square in athletic stance."],"execution_steps":["Open the lead hip and punch the outside foot into the ground.","Turn the pelvis and accelerate through the finish.","Alternate sides with full recovery."],"coach_cues":["Open, punch, go","Hips turn before shoulders chase","No false step"],"common_faults":["Crossing the feet","Standing tall before sprinting","Knee collapsing on the plant"]}'::jsonb),
  ('Flying 10m Sprint', 'flying-10m-sprint', 'Flying 10m Sprint is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes upright sprint cycle, front side mechanics, elastic foot contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 6, 180, 190, 'Classic max-velocity exposure: build in, sprint fast through a 10 m fly zone, and stop before fatigue compromises mechanics.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Max Velocity Exposure', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["upright_sprint_cycle","front_side_mechanics","elastic_foot_contact"],"primary_tissues":["hamstrings","calves","hip_flexors","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Classic max-velocity exposure: build in, sprint fast through a 10 m fly zone, and stop before fatigue compromises mechanics.","setup":["Set a 20-30 m build-in, 10 m fly zone, and 20 m decel zone.","Use clear cones and safe spacing."],"execution_steps":["Accelerate smoothly through the build-in.","Sprint fast and relaxed through the fly zone.","Decelerate gradually and rest fully."],"coach_cues":["Build, blast, relax","Step down under the hips","Fast but loose"],"common_faults":["Racing the build-in too early","Straining through the fly zone","Insufficient deceleration space"]}'::jsonb),
  ('Ins-and-Out Sprint Float-Sprint', 'ins-and-out-sprint-float-sprint', 'Ins-and-Out Sprint Float-Sprint is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes speed change control, upright sprint cycle, elastic contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 8, 180, 195, 'Sprint-float-sprint rhythm drill that teaches relaxation at high speed and re-acceleration without overstriding.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Max Velocity Exposure', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["speed_change_control","upright_sprint_cycle","elastic_contact"],"primary_tissues":["hamstrings","calves","hip_flexors","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Sprint-float-sprint rhythm drill that teaches relaxation at high speed and re-acceleration without overstriding.","setup":["Set zones: build-in, sprint, float, sprint, decel.","Use 10-20 m zones depending on athlete level."],"execution_steps":["Build smoothly into the first sprint zone.","Float without braking or jogging.","Re-accelerate smoothly through the second sprint zone and decel gradually."],"coach_cues":["Fast-relaxed-fast","Float tall, do not brake","Let speed come back smoothly"],"common_faults":["Float becomes a jog","Second sprint becomes tense","No deceleration space"]}'::jsonb),
  ('Wicket Run Max Velocity', 'wicket-run-max-velocity', 'Wicket Run Max Velocity is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes front side cycle, elastic foot contact, upright posture while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 6, 150, 160, 'Spaced cones or mini-wickets guide step rhythm, posture, and front-side mechanics at upright speed.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Wicket & Rhythm Runs', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["front_side_cycle","elastic_foot_contact","upright_posture"],"primary_tissues":["hamstrings","calves","hip_flexors","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Spaced cones or mini-wickets guide step rhythm, posture, and front-side mechanics at upright speed.","setup":["Place cones/wickets with conservative spacing for the athlete.","Create a build-in and a deceleration zone."],"execution_steps":["Build into the first wicket smoothly.","Run tall through the wickets, striking under the hip.","Maintain rhythm; stop if the athlete reaches or clips spacing."],"coach_cues":["Run over the ground, not at the cones","Tall hips","Step down under you"],"common_faults":["Spacing too aggressive","Overstriding to hit wickets","Looking down at the cones"]}'::jsonb),
  ('Straight-Leg Bounds to Sprint', 'straight-leg-bounds-to-sprint', 'Straight-Leg Bounds to Sprint is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes hip flexion extension, ankle stiffness, elastic ground contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 5, 120, 130, 'Straight-leg bounding pattern that links stiffness and front-side strike into a short acceleration or fly transition.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Max Velocity Projection Drills', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["hip_flexion_extension","ankle_stiffness","elastic_ground_contact"],"primary_tissues":["hamstrings","calves","glutes","hip_flexors"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Straight-leg bounding pattern that links stiffness and front-side strike into a short acceleration or fly transition.","setup":["Mark 10 m for straight-leg bounds and 10-20 m for transition sprint.","Begin tall with active arms."],"execution_steps":["Bound forward with relatively straight legs and stiff contacts under the hips.","Transition smoothly into sprint mechanics.","Walk back and recover fully."],"coach_cues":["Sweep down under the hip","Bounce tall","Transition, do not lunge"],"common_faults":["Locked knees with hard landings","Overreaching in front","Losing posture on transition"]}'::jsonb),
  ('Fast-Leg Cycle Drill', 'fast-leg-cycle-drill', 'Fast-Leg Cycle Drill is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes front side cycle, hip flexion, hamstring recovery while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 5, 20, 40, 65, 'Single-leg cycle drill that isolates rapid front-side recovery and strike timing for upright sprinting.', 'Primary subrole: locomotion_sprint_mechanics. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Sprint Drill Series', 'movement_intelligence', 'locomotion_sprint_mechanics', 'locomotion_sprint_mechanics', '{"primary_joint_actions":["front_side_cycle","hip_flexion","hamstring_recovery","foot_strike_timing"],"primary_tissues":["hip_flexors","hamstrings","calves"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Single-leg cycle drill that isolates rapid front-side recovery and strike timing for upright sprinting.","setup":["Stand tall or move slowly over 10-15 m.","One leg cycles while the other provides rhythm steps."],"execution_steps":["Cycle the drill leg up, through, and down under the hip.","Keep the opposite side smooth and balanced.","Switch sides after the prescribed distance or reps."],"coach_cues":["Heel up, knee through, strike down","Tall pelvis","Fast leg, quiet trunk"],"common_faults":["Casting foot forward","Rotating the torso","Chasing speed before timing"]}'::jsonb),
  ('Progressive Build-Up Sprint 30m', 'progressive-build-up-sprint-30m', 'Progressive Build-Up Sprint 30m is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes progressive acceleration, upright sprint cycle, elastic foot contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, NULL, 6, 120, 130, 'Controlled build-up that teaches smooth acceleration into upright mechanics without the pressure of an all-out fly rep.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Build-Up Runs', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["progressive_acceleration","upright_sprint_cycle","elastic_foot_contact"],"primary_tissues":["hamstrings","glutes","calves","hip_flexors"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Controlled build-up that teaches smooth acceleration into upright mechanics without the pressure of an all-out fly rep.","setup":["Set a 30 m lane and a deceleration zone.","Mark thirds if needed: smooth, fast, fastest."],"execution_steps":["Start relaxed and progressively increase speed.","Reach fast but smooth mechanics in the final third.","Decelerate gradually and repeat only when quality is high."],"coach_cues":["Smooth to fast","Relax into speed","Tall by the end"],"common_faults":["Sprinting all-out from step one","Tension in the shoulders and face","Stopping too abruptly"]}'::jsonb),
  ('Curve Sprint Build-Up', 'curve-sprint-build-up', 'Curve Sprint Build-Up is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes curved sprint lean, hip extension, elastic foot contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, NULL, 8, 150, 160, 'Curved sprint exposure for sprinters and field athletes who need speed while managing lean, posture, and inside-outside leg mechanics.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Build-Up Runs', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["curved_sprint_lean","hip_extension","elastic_foot_contact"],"primary_tissues":["glutes","hamstrings","calves","obliques"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Curved sprint exposure for sprinters and field athletes who need speed while managing lean, posture, and inside-outside leg mechanics.","setup":["Use a track curve or cone arc with generous radius.","Mark 20-40 m and a safe deceleration zone."],"execution_steps":["Build speed gradually into the curve.","Lean from the whole body, not the waist.","Maintain relaxed arms and step under the hips."],"coach_cues":["Lean as one piece","Tall inside hip","Run the curve, do not fight it"],"common_faults":["Bending at the waist","Crossing feet across the line","Curve too tight for speed"]}'::jsonb),
  ('Dribble Build to Sprint', 'dribble-build-to-sprint', 'Dribble Build to Sprint is a max velocity & rhythm exercise for speed, sprinting, and quick-release athletes. It emphasizes dribble transition, upright sprint cycle, elastic foot contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 1, 6, 150, 160, 'Transition drill that blends dribble mechanics into free sprinting so athletes carry rhythm into upright speed.', 'Primary subrole: max_velocity_exposure. Use this for athletes who need max velocity & rhythm without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Max Velocity Projection Drills', 'output', 'max_velocity_exposure', 'max_velocity_exposure', '{"primary_joint_actions":["dribble_transition","upright_sprint_cycle","elastic_foot_contact"],"primary_tissues":["hip_flexors","hamstrings","calves","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"setup_metadata":{"run_in":"progressive build-in required","deceleration_zone":"mandatory","quality_priority":"fast, relaxed, upright mechanics"}}'::jsonb, '{"movement_description":"Transition drill that blends dribble mechanics into free sprinting so athletes carry rhythm into upright speed.","setup":["Mark 10-15 m for dribble mechanics and 10-20 m for free sprinting.","Start tall with relaxed arms and clear deceleration space."],"execution_steps":["Begin with low-to-high dribble rhythm.","Blend smoothly into a free sprint without reaching or tensing.","Sprint through the cone, decelerate gradually, and rest fully."],"coach_cues":["Dribble, rise, sprint","Carry the rhythm","Fast but relaxed"],"common_faults":["Hard break between drill and sprint","Overstriding on the transition","Trying to sprint before rhythm is established"]}'::jsonb),
  ('Pogo Jumps', 'pogo-jumps', 'Pogo Jumps is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes ankle stiffness, forefoot contact, minimal knee bend while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 2, 20, 15, 45, 65, 'Low-amplitude bilateral contacts that develop ankle stiffness, rhythm, and fast ground exchange for sprinting.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Elastic Rudiments', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["ankle_stiffness","forefoot_contact","minimal_knee_bend"],"primary_tissues":["calves","soleus","achilles_tendon","plantar_intrinsics"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Low-amplitude bilateral contacts that develop ankle stiffness, rhythm, and fast ground exchange for sprinting.","setup":["Stand tall with feet hip-width and arms relaxed.","Choose a firm, safe surface."],"execution_steps":["Bounce vertically with small amplitude and stiff ankles.","Keep knees soft but quiet.","Stop when contacts get loud or posture drops."],"coach_cues":["Tall, quick, quiet","Bounce off the balls of the feet","Do not squat the pogo"],"common_faults":["Knees bending too much","Heels slamming down","Excessive volume chasing a burn"]}'::jsonb),
  ('Single-Leg Pogo', 'single-leg-pogo', 'Single-Leg Pogo is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes single leg ankle stiffness, hip stability, forefoot contact while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 2, 10, 10, 50, 65, 'Single-leg pogo that progresses elastic stiffness and foot-ankle robustness for sprint contacts.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Elastic Rudiments', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["single_leg_ankle_stiffness","hip_stability","forefoot_contact"],"primary_tissues":["calves","soleus","achilles_tendon","glute_med"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Single-leg pogo that progresses elastic stiffness and foot-ankle robustness for sprint contacts.","setup":["Stand tall on one leg with the knee softly unlocked.","Use a safe surface and enough space."],"execution_steps":["Bounce in place with low amplitude and a stiff ankle.","Maintain pelvis level and foot under the hip.","Switch sides and stop if contact quality fades."],"coach_cues":["Quiet spring","Hip stacked over foot","Quick off the ground"],"common_faults":["Knee collapsing inward","Hopping too high","Pushing through Achilles or foot pain"]}'::jsonb),
  ('Alternating Bounds', 'alternating-bounds', 'Alternating Bounds is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal projection, hip extension, elastic landing while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 8, 10, 90, 105, 'Alternating horizontal bounds that train projection, elastic stiffness, and coordinated arm-leg power.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Bounding', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["horizontal_projection","hip_extension","elastic_landing"],"primary_tissues":["glutes","hamstrings","calves","quads"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4}'::jsonb, '{"movement_description":"Alternating horizontal bounds that train projection, elastic stiffness, and coordinated arm-leg power.","setup":["Mark a 10-20 m lane with clear landing space.","Start tall with arms prepared."],"execution_steps":["Bound from one leg to the other with controlled horizontal projection.","Land under the hip and immediately project to the other leg.","Keep reps capped and rest fully."],"coach_cues":["Project, snap down, switch","Hips tall","Arms drive the bound"],"common_faults":["Reaching too far and braking","Knee collapse on landing","Using too many contacts"]}'::jsonb),
  ('Single-Leg Bounds', 'single-leg-bounds', 'Single-Leg Bounds is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes single leg horizontal projection, hip extension, elastic stiffness while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 5, 8, 120, 130, 'Higher-intensity single-leg bounding drill for advanced elastic projection and sprint-specific tissue stiffness.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Bounding', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["single_leg_horizontal_projection","hip_extension","elastic_stiffness"],"primary_tissues":["glutes","hamstrings","calves","quads"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":5}'::jsonb, '{"movement_description":"Higher-intensity single-leg bounding drill for advanced elastic projection and sprint-specific tissue stiffness.","setup":["Mark a short lane and choose a safe, forgiving surface.","Begin with a controlled approach or standing start."],"execution_steps":["Bound repeatedly on one leg with controlled projection.","Keep landings under the hip and posture tall.","Use very low volume and switch sides."],"coach_cues":["Stiff but not locked","Project from the hip","Land under you"],"common_faults":["Too much distance causing braking","Pelvis dropping","Using with unprepared Achilles/hamstrings"]}'::jsonb),
  ('Low Hurdle Hops', 'low-hurdle-hops', 'Low Hurdle Hops is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes bilateral elastic takeoff, ankle stiffness, landing rebound while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 6, 8, 90, 105, 'Low hurdle or cone hops that train quick elastic contacts with a controlled obstacle constraint.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Elastic Rudiments', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["bilateral_elastic_takeoff","ankle_stiffness","landing_rebound"],"primary_tissues":["calves","soleus","quads","glutes"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4}'::jsonb, '{"movement_description":"Low hurdle or cone hops that train quick elastic contacts with a controlled obstacle constraint.","setup":["Set 4-6 low hurdles, cones, or lines with conservative spacing.","Athlete starts tall with hands free or on hips."],"execution_steps":["Hop over each obstacle with minimal ground time.","Keep contacts quiet and posture stacked.","Walk back and rest before repeating."],"coach_cues":["Pop, pop, pop","Stay tall over the hurdles","Quiet feet"],"common_faults":["Obstacles too high","Deep knee bends between hops","Rushing into unsafe spacing"]}'::jsonb),
  ('Drop Jump Reactive', 'drop-jump-reactive', 'Drop Jump Reactive is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes landing rebound, ankle stiffness, hip knee extension while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 110, 'Reactive drop jump that trains short ground contact and vertical stiffness after a small drop.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Reactive Jumping', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_stiffness_plyometric_rudiments', '{"primary_joint_actions":["landing_rebound","ankle_stiffness","hip_knee_extension"],"primary_tissues":["calves","achilles_tendon","quads","glutes"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":5}'::jsonb, '{"movement_description":"Reactive drop jump that trains short ground contact and vertical stiffness after a small drop.","setup":["Use a low box appropriate to the athlete.","Stand tall at the edge with clear landing area."],"execution_steps":["Step off, land on both feet, and rebound quickly upward.","Keep ground contact short without collapsing.","Reset fully between attempts."],"coach_cues":["Step off, bounce up","Quiet and quick","Tall rebound"],"common_faults":["Jumping off the box instead of stepping","Deep squat on contact","Box too high"]}'::jsonb),
  ('Lateral Skater Bound Stick', 'lateral-skater-bound-stick', 'Lateral Skater Bound Stick is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes lateral projection, single leg landing, hip stability while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 3, 4, 25, 60, 90, 'Lateral bound with a controlled stick to build frontal-plane power, braking, and hip-knee-foot alignment.', 'Primary subrole: landing_braking_control. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Landing & Braking Control', 'resilience', 'landing_braking_control', 'landing_braking_control', '{"primary_joint_actions":["lateral_projection","single_leg_landing","hip_stability"],"primary_tissues":["glute_med","adductors","quads","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3,"cod_stress_profile":{"approach_velocity":"low_to_moderate unless marked output","cut_angle":"0-90 degrees depending on setup","quality_priority":"quiet stick, knee/hip/foot alignment"}}'::jsonb, '{"movement_description":"Lateral bound with a controlled stick to build frontal-plane power, braking, and hip-knee-foot alignment.","setup":["Create side-to-side space with optional cones for distance targets.","Stand on one leg with the opposite arm loaded."],"execution_steps":["Bound laterally and land on the opposite leg.","Stick for 2 seconds with knee tracking over toes.","Reset before bounding back."],"coach_cues":["Push away, land quiet","Knee over middle toes","Own the stick"],"common_faults":["Knee diving inward","Landing loud or drifting","Adding speed before control"]}'::jsonb),
  ('Snap-Down to Stick', 'snap-down-to-stick', 'Snap-Down to Stick is a elastic stiffness & plyometrics exercise for speed, sprinting, and quick-release athletes. It emphasizes rapid eccentric absorption, hip hinge, knee flexion while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 5, 20, 40, 65, 'Fast snap-down into a stable landing that teaches braking positions and stiffness-to-control transition.', 'Primary subrole: landing_braking_control. Use this for athletes who need elastic stiffness & plyometrics without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Landing & Braking Control', 'resilience', 'landing_braking_control', 'landing_braking_control', '{"primary_joint_actions":["rapid_eccentric_absorption","hip_hinge","knee_flexion","trunk_bracing"],"primary_tissues":["quads","glutes","calves","hamstrings"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":2,"cod_stress_profile":{"approach_velocity":"low_to_moderate unless marked output","cut_angle":"0-90 degrees depending on setup","quality_priority":"quiet stick, knee/hip/foot alignment"}}'::jsonb, '{"movement_description":"Fast snap-down into a stable landing that teaches braking positions and stiffness-to-control transition.","setup":["Stand tall on the balls of the feet with arms overhead.","Have enough space and a stable surface."],"execution_steps":["Snap arms down and drop into an athletic landing.","Stick the landing quietly with hips back and ribs stacked.","Reset and repeat only crisp reps."],"coach_cues":["Snap to athletic","Quiet feet, strong brakes","Knees track over toes"],"common_faults":["Knees collapse inward","Landing too deep or too stiff","Chest falling below hips"]}'::jsonb),
  ('Countermovement Jump', 'countermovement-jump', 'Countermovement Jump is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes rapid countermovement, triple extension, landing absorption while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 3, 10, 90, 110, 'Simple vertical jump output drill for lower-body power, rapid countermovement, and landing quality.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Jump Power', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["rapid_countermovement","triple_extension","landing_absorption"],"primary_tissues":["glutes","quads","calves","hamstrings"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Simple vertical jump output drill for lower-body power, rapid countermovement, and landing quality.","setup":["Stand tall with feet hip-width.","Choose arm swing or hands-on-hips depending on test intent."],"execution_steps":["Dip quickly into a quarter squat.","Jump vertically with maximal intent.","Land quietly and reset fully."],"coach_cues":["Fast dip, violent jump","Reach tall","Land like a ninja"],"common_faults":["Deep slow squat","Knees collapsing","Bouncing repeated reps without reset"]}'::jsonb),
  ('Standing Broad Jump', 'standing-broad-jump', 'Standing Broad Jump is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal projection, hip extension, landing absorption while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 3, 10, 90, 110, 'Horizontal jump that teaches projection angles, hip power, and two-foot landing control for acceleration transfer.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Jump Power', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["horizontal_projection","hip_extension","landing_absorption"],"primary_tissues":["glutes","hamstrings","quads","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":3}'::jsonb, '{"movement_description":"Horizontal jump that teaches projection angles, hip power, and two-foot landing control for acceleration transfer.","setup":["Stand behind a line with feet hip-width.","Clear a safe landing zone."],"execution_steps":["Load the hips and swing the arms back.","Jump forward with aggressive hip extension.","Land balanced and stick before stepping out."],"coach_cues":["Throw the arms, push the ground","Project forward","Stick the landing"],"common_faults":["Jumping too high with no projection","Collapsing on landing","Measuring distance at the expense of safe landing"]}'::jsonb),
  ('Triple Broad Jump', 'triple-broad-jump', 'Triple Broad Jump is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes repeated horizontal projection, landing rebound, hip extension while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 2, 10, 120, 140, 'Three connected broad jumps for repeated horizontal power, elastic projection, and controlled landings.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Jump Power', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["repeated_horizontal_projection","landing_rebound","hip_extension"],"primary_tissues":["glutes","hamstrings","quads","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":4}'::jsonb, '{"movement_description":"Three connected broad jumps for repeated horizontal power, elastic projection, and controlled landings.","setup":["Mark a start line and clear a long landing lane.","Stand tall with arms ready."],"execution_steps":["Perform three powerful horizontal jumps in sequence.","Absorb and re-project without collapsing.","Stick the final landing."],"coach_cues":["Power, power, stick","Hips through each jump","Land under control"],"common_faults":["Rushing contacts with poor landings","Knees diving inward","Too much volume"]}'::jsonb),
  ('Med Ball Chest Pass', 'med-ball-chest-pass', 'Med Ball Chest Pass is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal push, trunk bracing, scapular protraction while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 5, 15, 75, 95, 'Explosive chest pass that trains upper-body quick release, trunk stiffness, and rapid force transfer through the arms.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Medicine Ball Quick Release', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["horizontal_push","trunk_bracing","scapular_protraction"],"primary_tissues":["pecs","triceps","serratus","abdominals"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Explosive chest pass that trains upper-body quick release, trunk stiffness, and rapid force transfer through the arms.","setup":["Stand athletic facing a sturdy wall or partner.","Hold a light medicine ball at the chest."],"execution_steps":["Brace and throw the ball explosively from the chest.","Catch or retrieve, reset posture, and repeat.","Keep reps low and high intent."],"coach_cues":["Punch through the ball","Ribs down, hands fast","Throw, reset, repeat"],"common_faults":["Using a ball too heavy","Leaning back and losing brace","Turning it into a conditioning circuit"]}'::jsonb),
  ('Med Ball Scoop Toss', 'med-ball-scoop-toss', 'Med Ball Scoop Toss is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes hip hinge snap, triple extension, ball release while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 4, 15, 90, 110, 'Explosive underhand toss that teaches hip snap, whole-body extension, and release timing.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Medicine Ball Quick Release', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["hip_hinge_snap","triple_extension","ball_release"],"primary_tissues":["glutes","hamstrings","quads","abdominals","shoulders"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Explosive underhand toss that teaches hip snap, whole-body extension, and release timing.","setup":["Stand with feet hip-width holding a light medicine ball.","Use a clear throw zone or throw to a wall if appropriate."],"execution_steps":["Hinge quickly and load the hips.","Explode upward/forward and release the ball with intent.","Reset fully before the next throw."],"coach_cues":["Hips launch the ball","Snap tall","Throw, do not lift"],"common_faults":["Squatting too deep and slow","Throwing mostly with arms","Ball too heavy"]}'::jsonb),
  ('Med Ball Overhead Back Toss', 'med-ball-overhead-back-toss', 'Med Ball Overhead Back Toss is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, triple extension, overhead release while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 4, 15, 90, 110, 'Backward overhead medicine-ball throw that expresses triple extension power and hip-driven release.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Medicine Ball Quick Release', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["hip_extension","triple_extension","overhead_release"],"primary_tissues":["glutes","hamstrings","quads","lats","abdominals"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Backward overhead medicine-ball throw that expresses triple extension power and hip-driven release.","setup":["Stand with back facing the throw area.","Hold a light medicine ball between the legs and confirm no one is behind."],"execution_steps":["Dip/hinge quickly to load the hips.","Explode upward and backward, releasing the ball overhead.","Watch the landing area only after release and reset."],"coach_cues":["Launch with hips","Finish tall","Throw to the sky behind you"],"common_faults":["Throwing with the low back","Ball too heavy","Unsafe throw zone"]}'::jsonb),
  ('Med Ball Rotational Shot Put', 'med-ball-rotational-shot-put', 'Med Ball Rotational Shot Put is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes hip rotation, trunk rotation, horizontal push release while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 4, 15, 75, 95, 'Rotational medicine-ball throw that trains hip-to-trunk-to-arm sequencing for quick release athletes.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Medicine Ball Rotational Power', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["hip_rotation","trunk_rotation","horizontal_push_release"],"primary_tissues":["obliques","glutes","pecs","triceps","adductors"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Rotational medicine-ball throw that trains hip-to-trunk-to-arm sequencing for quick release athletes.","setup":["Stand perpendicular to a sturdy wall or open throw zone.","Hold a light medicine ball near the back hip/chest."],"execution_steps":["Load the back hip.","Rotate the hips and trunk, then punch the ball into the wall/space.","Reset and perform equal reps each side."],"coach_cues":["Hip leads, hand finishes","Throw through the wall","Brace after release"],"common_faults":["Arms throwing before hips","Over-rotating the low back","Heavy ball slowing the release"]}'::jsonb),
  ('Med Ball Step-Behind Rotational Throw', 'med-ball-step-behind-rotational-throw', 'Med Ball Step-Behind Rotational Throw is a quick-release throws & jump power exercise for speed, sprinting, and quick-release athletes. It emphasizes step behind weight shift, hip rotation, trunk rotation while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 3, 15, 90, 110, 'Dynamic step-behind throw that adds footwork, separation, and rotational quick release to medicine-ball power.', 'Primary subrole: jump_throw_explosive_power. Use this for athletes who need quick-release throws & jump power without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Medicine Ball Rotational Power', 'output', 'jump_throw_explosive_power', 'jump_throw_explosive_power', '{"primary_joint_actions":["step_behind_weight_shift","hip_rotation","trunk_rotation","release"],"primary_tissues":["obliques","glutes","adductors","pecs","triceps"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Dynamic step-behind throw that adds footwork, separation, and rotational quick release to medicine-ball power.","setup":["Stand side-on to a wall or open field with a light medicine ball.","Create enough space for a step-behind entry."],"execution_steps":["Step behind to load the back hip.","Drive the hips through and release the ball explosively.","Reset before the next attempt; train both sides."],"coach_cues":["Feet load the hips","Separate, then fire","Fast finish"],"common_faults":["Rushing footwork","Throwing around the body instead of through the target","Too heavy a ball"]}'::jsonb),
  ('Trap Bar Deadlift', 'trap-bar-deadlift', 'Trap Bar Deadlift is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes hip extension, knee extension, trunk bracing while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 4, 20, 120, 145, 'High-output lower-body strength pattern that builds force capacity for acceleration without the technical barrier of a straight-bar deadlift.', 'Primary subrole: hinge_posterior_chain_strength. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Speed Strength Capacity', 'capacity', 'hinge_posterior_chain_strength', 'hinge_posterior_chain_strength', '{"primary_joint_actions":["hip_extension","knee_extension","trunk_bracing"],"primary_tissues":["glutes","hamstrings","quads","spinal_erectors"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"High-output lower-body strength pattern that builds force capacity for acceleration without the technical barrier of a straight-bar deadlift.","setup":["Stand centered in the trap bar with handles even.","Set feet under hips and brace the trunk."],"execution_steps":["Push the floor away and stand tall with hips and knees extending together.","Lower with control while maintaining neutral spine.","Keep reps powerful and non-grindy."],"coach_cues":["Push the floor","Chest proud, ribs down","Finish tall, no lean back"],"common_faults":["Jerking off the floor","Knees collapsing inward","Grinding to failure"]}'::jsonb),
  ('Rear-Foot Elevated Split Squat', 'rear-foot-elevated-split-squat', 'Rear-Foot Elevated Split Squat is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes single leg knee extension, hip extension, trunk bracing while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 6, 35, 90, 130, 'Unilateral strength drill for sprint-relevant force capacity, hip stability, and leg strength symmetry.', 'Primary subrole: squat_knee_dominant_strength. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Unilateral Strength Capacity', 'capacity', 'squat_knee_dominant_strength', 'squat_knee_dominant_strength', '{"primary_joint_actions":["single_leg_knee_extension","hip_extension","trunk_bracing"],"primary_tissues":["quads","glutes","adductors","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"Unilateral strength drill for sprint-relevant force capacity, hip stability, and leg strength symmetry.","setup":["Place rear foot on a low box/bench and front foot far enough to control shin angle.","Hold bodyweight or dumbbells."],"execution_steps":["Lower under control into the front leg.","Drive through the front foot to stand tall.","Keep pelvis level and knee tracking over toes."],"coach_cues":["Front leg does the work","Knee tracks, hips square","Drive the floor away"],"common_faults":["Pushing off the rear foot","Front knee collapsing","Excessive forward torso collapse"]}'::jsonb),
  ('Romanian Deadlift', 'romanian-deadlift', 'Romanian Deadlift is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes hip hinge, eccentric hamstring loading, trunk bracing while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 6, 35, 90, 130, 'Hip-hinge strength drill that develops hamstring and glute capacity for sprinting and force projection.', 'Primary subrole: hinge_posterior_chain_strength. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Posterior Chain Capacity', 'capacity', 'hinge_posterior_chain_strength', 'hinge_posterior_chain_strength', '{"primary_joint_actions":["hip_hinge","eccentric_hamstring_loading","trunk_bracing"],"primary_tissues":["hamstrings","glutes","spinal_erectors"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hip-hinge strength drill that develops hamstring and glute capacity for sprinting and force projection.","setup":["Hold a barbell or dumbbells in front of the thighs.","Stand tall with knees slightly unlocked and ribs stacked."],"execution_steps":["Push hips back while keeping the spine long.","Lower until hamstrings are loaded without losing position.","Drive hips forward to stand tall."],"coach_cues":["Hips back, shins quiet","Feel hamstrings load","Stand by squeezing glutes"],"common_faults":["Squatting instead of hinging","Rounding the back","Chasing range beyond control"]}'::jsonb),
  ('Heavy Sled Push March', 'heavy-sled-push-march', 'Heavy Sled Push March is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes horizontal drive, hip extension, knee drive while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, NULL, 20, 120, 145, 'Heavy marching sled push builds horizontal force and acceleration posture without the speed demand of sprinting.', 'Primary subrole: hinge_posterior_chain_strength. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Horizontal Force Capacity', 'capacity', 'hinge_posterior_chain_strength', 'hinge_posterior_chain_strength', '{"primary_joint_actions":["horizontal_drive","hip_extension","knee_drive","trunk_bracing"],"primary_tissues":["glutes","quads","calves","hamstrings"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"Heavy marching sled push builds horizontal force and acceleration posture without the speed demand of sprinting.","setup":["Load the sled heavy enough to march but not so heavy posture breaks.","Use a straight 10-20 m lane."],"execution_steps":["Lean into the sled with a long body line.","March with powerful, deliberate steps.","Rest long enough to preserve force quality."],"coach_cues":["Drive the turf back","Long line, strong arms","Big pushes, not tiny steps"],"common_faults":["Turning it into a gas-out finisher","Hips too high or low","Steps too short to express force"]}'::jsonb),
  ('Hang Power Clean from High Hang', 'hang-power-clean-from-high-hang', 'Hang Power Clean from High Hang is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes explosive hip extension, triple extension, front rack receive while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 4, 3, 15, 150, 170, 'Advanced barbell power exercise for rapid hip extension and total-body force transfer when technical coaching is available.', 'Primary subrole: hinge_posterior_chain_strength. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Olympic Power Development', 'capacity', 'hinge_posterior_chain_strength', 'hinge_posterior_chain_strength', '{"primary_joint_actions":["explosive_hip_extension","triple_extension","front_rack_receive"],"primary_tissues":["glutes","hamstrings","quads","traps","forearms"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Advanced barbell power exercise for rapid hip extension and total-body force transfer when technical coaching is available.","setup":["Start from high hang with bar at upper thigh.","Set lats, brace, and keep feet under hips."],"execution_steps":["Dip slightly and extend violently through hips, knees, and ankles.","Pull under and receive the bar in a partial front squat.","Stand tall, reset, and keep reps crisp."],"coach_cues":["Jump then punch elbows through","Bar stays close","Fast, not heavy and slow"],"common_faults":["Early arm pull","Crashing the bar in the rack","Loading too heavy for speed or skill"]}'::jsonb),
  ('Nordic Hamstring Eccentric', 'nordic-hamstring-eccentric', 'Nordic Hamstring Eccentric is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes eccentric knee flexion control, trunk bracing, hip extension hold while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 4, 25, 90, 120, 'High-value hamstring eccentric drill for posterior-chain resilience and sprint injury-risk reduction support.', 'Primary subrole: slow_eccentric_isometric_joint_resilience. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Hamstring Resilience', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'slow_eccentric_isometric_joint_resilience', '{"primary_joint_actions":["eccentric_knee_flexion_control","trunk_bracing","hip_extension_hold"],"primary_tissues":["hamstrings","glutes","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"sport_ready_projected_or_upright_sprint_shape","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"moderate","impact_level":0,"joint_resilience_profile":{"tissue_target":["hamstrings","glutes","calves"],"tempo_or_hold":"slow eccentric or controlled hold","soreness_risk":"dose conservatively around sprint days"}}'::jsonb, '{"movement_description":"High-value hamstring eccentric drill for posterior-chain resilience and sprint injury-risk reduction support.","setup":["Kneel on a mat with ankles anchored by partner or equipment.","Keep hips extended and ribs stacked."],"execution_steps":["Lower the body forward as slowly as control allows.","Catch with hands and push lightly back to start.","Keep reps low and stop before cramping or pain."],"coach_cues":["Long body line","Slow fall, strong hamstrings","Catch, reset"],"common_faults":["Breaking at the hips","Too much volume too soon","Forcing through hamstring pain"]}'::jsonb),
  ('Seated Soleus Raise', 'seated-soleus-raise', 'Seated Soleus Raise is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes plantar flexion knee bent, controlled eccentric, ankle stability while keeping the session intent aligned with the Vortex phase sequence.', 'INTERMEDIATE', 8, 3, 12, 35, 60, 100, 'Bent-knee calf strength drill targeting soleus capacity for sprint stance support and elastic contacts.', 'Primary subrole: tissue_capacity_isometric_eccentric_accessory. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Foot-Ankle Capacity', 'capacity', 'tissue_capacity_isometric_eccentric_accessory', 'tissue_capacity_isometric_eccentric_accessory', '{"primary_joint_actions":["plantar_flexion_knee_bent","controlled_eccentric","ankle_stability"],"primary_tissues":["soleus","achilles_tendon","calves"],"primary_motor_control_demands":["bracing","force_absorption","alignment_control"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Bent-knee calf strength drill targeting soleus capacity for sprint stance support and elastic contacts.","setup":["Sit with knees bent around 90 degrees and forefoot on a small plate or floor.","Place a dumbbell or load over the thighs if appropriate."],"execution_steps":["Raise heels as high as controlled.","Pause briefly at the top.","Lower slowly and maintain pressure through big toe mound."],"coach_cues":["Drive through the ball of the foot","Own the top","Lower with control"],"common_faults":["Rolling to outside edge","Bouncing without control","Using load that irritates Achilles"]}'::jsonb),
  ('Banded Hip Flexor March', 'banded-hip-flexor-march', 'Banded Hip Flexor March is a speed strength & tissue capacity exercise for speed, sprinting, and quick-release athletes. It emphasizes resisted hip flexion, trunk bracing, pelvic control while keeping the session intent aligned with the Vortex phase sequence.', 'BEGINNER', 8, 2, 8, 25, 30, 60, 'Low-fatigue resisted march that primes hip flexor drive and pelvic control before sprint mechanics.', 'Primary subrole: activate. Use this for athletes who need speed strength & tissue capacity without confusing speed output with conditioning.', 'Fast, crisp, and clean. Stop before the rep gets slow or sloppy.', 'Hip Flexor Activation', 'prepare_and_access', 'activate', 'activate', '{"primary_joint_actions":["resisted_hip_flexion","trunk_bracing","pelvic_control"],"primary_tissues":["hip_flexors","abdominals","glutes"],"primary_motor_control_demands":["posture_control","rhythm_timing","force_direction"],"postural_shape":"stacked_ribs_over_pelvis","breathing_demand":"brace_then_breathe; no breath-holding during repeated reps","balance_demand":"single_leg_or_dynamic","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Low-fatigue resisted march that primes hip flexor drive and pelvic control before sprint mechanics.","setup":["Loop a light band around the feet or anchor it low behind the athlete.","Stand tall with light support if needed."],"execution_steps":["Brace and drive one knee up against the band.","Pause briefly without leaning back.","Lower with control and alternate sides."],"coach_cues":["Knee up, ribs down","Tall through the stance leg","Move the thigh, not the spine"],"common_faults":["Leaning back to lift the knee","Band too heavy","Hip flexor cramping from too much volume"]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

